#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        if (N % 2 == 1 && M % 2 == 1) {
            printf("IMPOSSIBLE\n");
        } else {
            printf("1 2\n");
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    if ((i + j) % 2 == 0) {
                        printf("a");
                    } else {
                        printf("b");
                    }
                }
                printf("\n");
            }
        }
    }
    return 0;
}

